"""Simulación de clientes móviles para el experimento federado.Este módulo define:- una estructura simple para representar un cliente muestreado,- un simulador de flota móvil,- y la lógica de muestreo sin reemplazo dentro de cada ronda.La idea es que cada ronda federada seleccione varios clientes, y que cadacliente disponga de un pequeño subconjunto de imágenes del pool global."""from __future__ import annotationsimport randomfrom collections import defaultdictfrom dataclasses import dataclass, fieldfrom typing import Dict, List, Optionalimport pandas as pd@dataclassclass ClientSample:    """    Representa un cliente móvil muestreado en una ronda federada.    Attributes    ----------    client_id : int        Identificador del cliente dentro de la ronda.    row_indices : List[int]        Índices de las filas del DataFrame del pool asignadas al cliente.    """    client_id: int    row_indices: List[int]@dataclassclass MobileFleetSimulator:    """    Simulador de flota de clientes móviles.    Parameters    ----------    df_pool : pd.DataFrame        DataFrame con las muestras disponibles para los clientes móviles.        Debe contener al menos la columna 'dx'.    random_state : int        Semilla aleatoria para reproducibilidad.    """    df_pool: pd.DataFrame    random_state: int = 42    rng: random.Random = field(init=False)    def __post_init__(self) -> None:        """        Inicializa el generador aleatorio y construye un índice por clase.        """        self.rng = random.Random(self.random_state)        self.df_pool = self.df_pool.reset_index(drop=True)        self.class_to_indices: Dict[str, List[int]] = defaultdict(list)        for idx, row in self.df_pool.iterrows():            self.class_to_indices[str(row["dx"])].append(idx)        self.classes = sorted(self.class_to_indices.keys())    def sample_clients_without_replacement(        self,        num_clients: int,        images_per_client: int,        class_bias: float = 0.6,    ) -> List[ClientSample]:        """        Muestrea clientes sin reemplazo dentro de una ronda.        Esto significa que una misma imagen no puede ser asignada a dos        clientes distintos en la misma ronda.        El parámetro class_bias introduce heterogeneidad no-IID:        - valores bajos generan clientes más parecidos entre sí,        - valores altos generan clientes más sesgados hacia una clase dominante.        Parameters        ----------        num_clients : int            Número de clientes a simular en la ronda.        images_per_client : int            Número de imágenes asignadas a cada cliente.        class_bias : float            Probabilidad de elegir una muestra de la clase dominante del cliente.        Returns        -------        List[ClientSample]            Lista de clientes simulados para la ronda.        """        available_global = set(self.df_pool.index.tolist())        clients: List[ClientSample] = []        for client_id in range(num_clients):            if not available_global:                break            dominant_class = self.rng.choice(self.classes)            chosen_indices: List[int] = []            for _ in range(images_per_client):                if not available_global:                    break                use_dominant = self.rng.random() < class_bias                candidate_idx: Optional[int] = None                if use_dominant:                    dominant_candidates = [                        idx                        for idx in self.class_to_indices[dominant_class]                        if idx in available_global                    ]                    if dominant_candidates:                        candidate_idx = self.rng.choice(dominant_candidates)                if candidate_idx is None:                    candidate_idx = self.rng.choice(list(available_global))                chosen_indices.append(candidate_idx)                available_global.remove(candidate_idx)            if chosen_indices:                clients.append(ClientSample(client_id=client_id, row_indices=chosen_indices))        return clients